// AnaSayfa.js
import React from 'react';
import Navbar from './components/Navbar';
import Sidebar from './components/Sidebar';

const AnaSayfa = () => {
  return (
    <div>
      <Navbar />
      <div style={styles.container}>
        <Sidebar />
        <main style={styles.main}>
          <h2>Hoş Geldiniz!</h2>
          <p>Burası Ana Sayfa içeriği.</p>
        </main>
      </div>
    </div>
  );
};

const styles = {
  container: {
    display: 'flex',
  },
  main: {
    flexGrow: 1,
    padding: '20px',
  },
};

export default AnaSayfa;
